131	#[derive(Clone, Copy, Debug)]
132	pub struct Clause {
133	    pub kind: ClauseKind,
134	    pub head: Term,
135	    pub body: BoundedArr<Term, MAX_BODY>,
136	    pub subterms: BoundedArr<Term, MAX_SUBTERMS>,
137	    pub vars: VarTable,
138	}
139	
140	impl Clause {
141	    pub const fn new() -> Self {
142	        Self {
143	            kind: ClauseKind::Fact,
144	            head: Term::Nil,
145	            body: BoundedArr::new(),
146	            subterms: BoundedArr::new(),
147	            vars: VarTable::new(),
148	        }
149	    }
150	
151	    pub fn subterm(&self, idx: TermIdx) -> Option<&Term> {
152	        self.subterms.get(idx as usize)
153	    }
154	}
155	
156	impl Default for Clause {
157	    fn default() -> Self {
158	        Self::new()
159	    }
160	}
