1	//! Lexical analysis for the Prolog subset.
2	//!
3	//! Hand-written scanner over `&str` bytes. Token spellings mirror
4	//! `tokenize.sno` (ATOM, VAR, INT, NECK, LPAREN, RPAREN, COMMA, DOT, ...)
5	//! so the SNOBOL4 port is mechanical. Control flow is goto-shaped:
6	//! a top-level loop skips whitespace/comments, then `next_token`
7	//! dispatches by first byte to one of a small set of scan helpers.
8	
9	use crate::port::{BoundedArr, BoundedStr};
10	use thiserror::Error;
11	
12	pub const MAX_TOKENS: usize = 512;
13	pub const ATOM_CAP: usize = 32;
14	
15	#[derive(Clone, Copy, Debug, PartialEq, Eq)]
16	pub enum Token {
17	    Atom(BoundedStr<ATOM_CAP>),
18	    Var(BoundedStr<ATOM_CAP>),
19	    Int(i32),
20	    LParen,
21	    RParen,
22	    LBracket,
23	    RBracket,
24	    Comma,
25	    Dot,
26	    Pipe,
27	    Neck,
28	    Cut,
29	    Not,
30	    Query,
31	    Eof,
32	}
33	
34	#[derive(Debug, Error, Clone, Copy, PartialEq, Eq)]
35	pub enum TokenizeError {
36	    #[error("unterminated block comment at position {pos}")]
37	    UnterminatedBlockComment { pos: usize },
38	    #[error("invalid character {ch:?} at position {pos}")]
39	    InvalidChar { ch: char, pos: usize },
40	    #[error("bad integer at position {pos}")]
41	    BadInt { pos: usize },
42	    #[error("integer out of range at position {pos}")]
43	    IntOverflow { pos: usize },
44	    #[error("identifier too long at position {pos}")]
45	    IdentTooLong { pos: usize },
46	    #[error("too many tokens (exceeded capacity)")]
47	    Overflow,
48	}
49	
50	struct Cursor<'a> {
51	    bytes: &'a [u8],
52	    pos: usize,
53	}
54	
55	impl<'a> Cursor<'a> {
56	    fn peek(&self) -> Option<u8> {
57	        self.bytes.get(self.pos).copied()
58	    }
59	
60	    fn peek_at(&self, offset: usize) -> Option<u8> {
61	        self.bytes.get(self.pos + offset).copied()
62	    }
63	
64	    fn at_end(&self) -> bool {
65	        self.pos >= self.bytes.len()
66	    }
67	}
68	
69	pub fn tokenize(src: &str) -> Result<BoundedArr<Token, MAX_TOKENS>, TokenizeError> {
70	    let mut cur = Cursor { bytes: src.as_bytes(), pos: 0 };
71	    let mut out: BoundedArr<Token, MAX_TOKENS> = BoundedArr::new();
72	    loop {
73	        skip_ws_and_comments(&mut cur)?;
74	        if cur.at_end() {
75	            break;
76	        }
77	        let tok = next_token(&mut cur)?;
78	        out.push(tok).map_err(|_| TokenizeError::Overflow)?;
79	    }
80	    out.push(Token::Eof).map_err(|_| TokenizeError::Overflow)?;
81	    Ok(out)
82	}
83	
84	fn skip_ws_and_comments(cur: &mut Cursor) -> Result<(), TokenizeError> {
85	    loop {
86	        match cur.peek() {
87	            Some(b' ') | Some(b'\t') | Some(b'\n') | Some(b'\r') => {
88	                cur.pos += 1;
89	            }
90	            Some(b'%') => skip_line_comment(cur),
91	            Some(b'/') if cur.peek_at(1) == Some(b'*') => skip_block_comment(cur)?,
92	            _ => return Ok(()),
93	        }
94	    }
95	}
96	
97	fn skip_line_comment(cur: &mut Cursor) {
98	    while let Some(b) = cur.peek() {
99	        cur.pos += 1;
100	        if b == b'\n' {
101	            return;
102	        }
103	    }
104	}
105	
106	fn skip_block_comment(cur: &mut Cursor) -> Result<(), TokenizeError> {
107	    let start = cur.pos;
108	    cur.pos += 2;
109	    loop {
110	        match cur.peek() {
111	            None => return Err(TokenizeError::UnterminatedBlockComment { pos: start }),
112	            Some(b'*') if cur.peek_at(1) == Some(b'/') => {
113	                cur.pos += 2;
114	                return Ok(());
115	            }
116	            Some(_) => cur.pos += 1,
117	        }
118	    }
119	}
120	
121	fn next_token(cur: &mut Cursor) -> Result<Token, TokenizeError> {
122	    let start = cur.pos;
123	    let c = cur.peek().expect("next_token called at end");
124	    if c == b':' && cur.peek_at(1) == Some(b'-') {
125	        cur.pos += 2;
126	        return Ok(Token::Neck);
127	    }
128	    if c == b'?' && cur.peek_at(1) == Some(b'-') {
129	        cur.pos += 2;
130	        return Ok(Token::Query);
131	    }
132	    if c == b'\\' && cur.peek_at(1) == Some(b'+') {
133	        cur.pos += 2;
134	        return Ok(Token::Not);
135	    }
136	    if c == b'-' && cur.peek_at(1).map(|b| b.is_ascii_digit()).unwrap_or(false) {
137	        return scan_int(cur);
138	    }
139	    if let Some(t) = punct_token(c) {
140	        cur.pos += 1;
141	        return Ok(t);
142	    }
143	    if c.is_ascii_digit() {
144	        return scan_int(cur);
145	    }
146	    if c.is_ascii_lowercase() {
147	        return scan_atom(cur);
148	    }
149	    if c.is_ascii_uppercase() || c == b'_' {
150	        return scan_var(cur);
151	    }
152	    Err(TokenizeError::InvalidChar { ch: c as char, pos: start })
153	}
154	
155	fn punct_token(c: u8) -> Option<Token> {
156	    match c {
157	        b'(' => Some(Token::LParen),
158	        b')' => Some(Token::RParen),
159	        b'[' => Some(Token::LBracket),
160	        b']' => Some(Token::RBracket),
161	        b',' => Some(Token::Comma),
162	        b'.' => Some(Token::Dot),
163	        b'|' => Some(Token::Pipe),
164	        b'!' => Some(Token::Cut),
165	        _ => None,
166	    }
167	}
168	
169	fn scan_ident_bytes<'a>(cur: &mut Cursor<'a>) -> &'a [u8] {
170	    let start = cur.pos;
171	    while let Some(b) = cur.peek() {
172	        if b.is_ascii_alphanumeric() || b == b'_' {
173	            cur.pos += 1;
174	        } else {
175	            break;
176	        }
177	    }
178	    &cur.bytes[start..cur.pos]
179	}
180	
181	fn scan_atom(cur: &mut Cursor) -> Result<Token, TokenizeError> {
182	    let start = cur.pos;
183	    let bytes = scan_ident_bytes(cur);
184	    let s = core::str::from_utf8(bytes).expect("ascii ident is valid utf8");
185	    let name = BoundedStr::<ATOM_CAP>::from_str(s)
186	        .map_err(|_| TokenizeError::IdentTooLong { pos: start })?;
187	    Ok(Token::Atom(name))
188	}
189	
190	fn scan_var(cur: &mut Cursor) -> Result<Token, TokenizeError> {
191	    let start = cur.pos;
192	    let bytes = scan_ident_bytes(cur);
193	    let s = core::str::from_utf8(bytes).expect("ascii ident is valid utf8");
194	    let name = BoundedStr::<ATOM_CAP>::from_str(s)
195	        .map_err(|_| TokenizeError::IdentTooLong { pos: start })?;
196	    Ok(Token::Var(name))
197	}
198	
199	fn scan_int(cur: &mut Cursor) -> Result<Token, TokenizeError> {
200	    let start = cur.pos;
201	    if cur.peek() == Some(b'-') {
202	        cur.pos += 1;
203	    }
204	    let digits_start = cur.pos;
205	    while let Some(b) = cur.peek() {
206	        if b.is_ascii_digit() {
207	            cur.pos += 1;
208	        } else {
209	            break;
210	        }
211	    }
212	    if cur.pos == digits_start {
213	        return Err(TokenizeError::BadInt { pos: start });
214	    }
215	    let s = core::str::from_utf8(&cur.bytes[start..cur.pos])
216	        .expect("ascii digits are valid utf8");
217	    s.parse::<i32>()
218	        .map(Token::Int)
219	        .map_err(|_| TokenizeError::IntOverflow { pos: start })
220	}
221	
222	#[cfg(test)]
223	mod tests {
224	    use super::*;
225	
226	    fn bs(s: &str) -> BoundedStr<ATOM_CAP> {
227	        BoundedStr::<ATOM_CAP>::from_str(s).expect("test name fits")
228	    }
229	
230	    fn tok_vec(src: &str) -> Vec<Token> {
231	        let arr = tokenize(src).expect("tokenize ok");
232	        arr.iter().copied().collect()
233	    }
234	
235	    #[test]
236	    fn empty_source_emits_only_eof() {
237	        let v = tok_vec("");
238	        assert_eq!(v, vec![Token::Eof]);
239	    }
240	
241	    #[test]
242	    fn whitespace_only() {
243	        let v = tok_vec("   \n\t  \r\n");
244	        assert_eq!(v, vec![Token::Eof]);
245	    }
246	
247	    #[test]
248	    fn atoms_vars_ints() {
249	        let v = tok_vec("foo Bar _baz 42 -7");
250	        assert_eq!(
251	            v,
252	            vec![
253	                Token::Atom(bs("foo")),
254	                Token::Var(bs("Bar")),
255	                Token::Var(bs("_baz")),
256	                Token::Int(42),
257	                Token::Int(-7),
258	                Token::Eof,
259	            ]
260	        );
261	    }
262	
